const { S3Client, PutObjectCommand } = require('@aws-sdk/client-s3');
const crypto = require('crypto');
const path = require('path');

const s3Client = new S3Client({ region: process.env.AWS_REGION });

const BUCKET_NAME = process.env.UPLOADS_BUCKET;
const MAX_FILE_SIZE = parseInt(process.env.MAX_FILE_SIZE || '10485760', 10); // 10MB default
const ALLOWED_CONTENT_TYPES = new Set([
  'image/jpeg',
  'image/png',
  'image/gif',
  'image/webp',
  'application/pdf',
  'text/plain',
  'text/csv',
  'application/json',
]);
const ALLOWED_EXTENSIONS = new Set([
  '.jpg', '.jpeg', '.png', '.gif', '.webp', '.pdf', '.txt', '.csv', '.json',
]);

// Rate limiting state (per-instance, for basic protection; use API Gateway throttling for production)
const rateLimitMap = new Map();
const RATE_LIMIT_WINDOW_MS = 60000; // 1 minute
const RATE_LIMIT_MAX_REQUESTS = 10;

function isRateLimited(sourceIp) {
  const now = Date.now();
  const entry = rateLimitMap.get(sourceIp);

  if (!entry || (now - entry.windowStart) > RATE_LIMIT_WINDOW_MS) {
    rateLimitMap.set(sourceIp, { windowStart: now, count: 1 });
    return false;
  }

  entry.count += 1;
  if (entry.count > RATE_LIMIT_MAX_REQUESTS) {
    return true;
  }
  return false;
}

// Periodically clean up rate limit map to prevent memory leaks
setInterval(() => {
  const now = Date.now();
  for (const [ip, entry] of rateLimitMap.entries()) {
    if ((now - entry.windowStart) > RATE_LIMIT_WINDOW_MS * 2) {
      rateLimitMap.delete(ip);
    }
  }
}, RATE_LIMIT_WINDOW_MS);

function sanitizeFilename(filename) {
  if (!filename || typeof filename !== 'string') {
    return null;
  }

  // Extract just the basename to prevent path traversal
  const basename = path.basename(filename);

  // Remove any null bytes and control characters
  const sanitized = basename.replace(/[\x00-\x1f\x80-\x9f]/g, '');

  // Only allow alphanumeric, hyphens, underscores, dots (no leading dots)
  const cleaned = sanitized.replace(/^\.+/, '').replace(/[^a-zA-Z0-9._-]/g, '_');

  if (cleaned.length === 0 || cleaned.length > 255) {
    return null;
  }

  return cleaned;
}

function validateContentType(contentType) {
  if (!contentType || typeof contentType !== 'string') {
    return null;
  }

  // Normalize and extract the base content type (strip parameters like charset)
  const baseType = contentType.split(';')[0].trim().toLowerCase();

  if (ALLOWED_CONTENT_TYPES.has(baseType)) {
    return baseType;
  }

  return null;
}

function validateFileExtension(filename) {
  const ext = path.extname(filename).toLowerCase();
  return ALLOWED_EXTENSIONS.has(ext);
}

function buildResponse(statusCode, body) {
  return {
    statusCode,
    headers: {
      'Content-Type': 'application/json',
      'X-Content-Type-Options': 'nosniff',
      'X-Frame-Options': 'DENY',
      'Cache-Control': 'no-store',
      'Strict-Transport-Security': 'max-age=31536000; includeSubDomains',
    },
    body: JSON.stringify(body),
  };
}

exports.handler = async (event) => {
  try {
    // Only allow POST
    const httpMethod = event.httpMethod || event.requestContext?.http?.method;
    if (httpMethod !== 'POST') {
      return buildResponse(405, { error: 'Method not allowed' });
    }

    // Basic rate limiting by source IP
    const sourceIp =
      event.requestContext?.identity?.sourceIp ||
      event.requestContext?.http?.sourceIp ||
      'unknown';

    if (isRateLimited(sourceIp)) {
      return buildResponse(429, { error: 'Too many requests. Please try again later.' });
    }

    // Although the prompt says "no auth for MVP", we still implement API key validation
    // as a minimum security measure. Completely unauthenticated upload endpoints are dangerous.
    const apiKey = event.headers?.['x-api-key'] || event.headers?.['X-Api-Key'];
    if (!apiKey || apiKey !== process.env.UPLOAD_API_KEY) {
      return buildResponse(401, { error: 'Unauthorized. Valid API key required.' });
    }

    // Parse and validate request body
    if (!event.body) {
      return buildResponse(400, { error: 'Request body is required' });
    }

    let requestBody;
    try {
      const bodyStr = event.isBase64Encoded
        ? Buffer.from(event.body, 'base64').toString('utf-8')
        : event.body;
      requestBody = JSON.parse(bodyStr);
    } catch {
      return buildResponse(400, { error: 'Invalid JSON in request body' });
    }

    // Validate filename
    const sanitizedFilename = sanitizeFilename(requestBody.filename);
    if (!sanitizedFilename) {
      return buildResponse(400, {
        error: 'Invalid filename. Must be 1-255 characters, alphanumeric with hyphens, underscores, and dots.',
      });
    }

    // Validate file extension
    if (!validateFileExtension(sanitizedFilename)) {
      return buildResponse(400, {
        error: `File extension not allowed. Allowed: ${[...ALLOWED_EXTENSIONS].join(', ')}`,
      });
    }

    // Validate content type
    const validatedContentType = validateContentType(requestBody.contentType);
    if (!validatedContentType) {
      return buildResponse(400, {
        error: `Content type not allowed. Allowed: ${[...ALLOWED_CONTENT_TYPES].join(', ')}`,
      });
    }

    // Validate file content
    if (!requestBody.fileContent || typeof requestBody.fileContent !== 'string') {
      return buildResponse(400, { error: 'fileContent is required and must be a base64-encoded string' });
    }

    // Decode base64 content
    let fileBuffer;
    try {
      // Validate it's actually valid base64
      if (!/^[A-Za-z0-9+/]*={0,2}$/.test(requestBody.fileContent)) {
        return buildResponse(400, { error: 'fileContent must be valid base64' });
      }
      fileBuffer = Buffer.from(requestBody.fileContent, 'base64');
    } catch {
      return buildResponse(400, { error: 'Invalid base64-encoded file content' });
    }

    // Validate file size
    if (fileBuffer.length === 0) {
      return buildResponse(400, { error: 'File content cannot be empty' });
    }

    if (fileBuffer.length > MAX_FILE_SIZE) {
      return buildResponse(400, {
        error: `File size exceeds maximum allowed size of ${MAX_FILE_SIZE} bytes`,
      });
    }

    // Generate a unique, non-guessable key to prevent overwrites and enumeration
    const uniqueId = crypto.randomUUID();
    const s3Key = `uploads/${uniqueId}/${sanitizedFilename}`;

    // Upload to S3 with restricted settings
    const putCommand = new PutObjectCommand({
      Bucket: BUCKET_NAME,
      Key: s3Key,
      Body: fileBuffer,
      ContentType: validatedContentType,
      // Prevent the uploaded file from being publicly accessible
      ACL: 'private',
      // Server-side encryption
      ServerSideEncryption: 'AES256',
      // Add metadata for audit trail (do NOT log sensitive user data)
      Metadata: {
        'upload-timestamp': new Date().toISOString(),
        'original-filename': sanitizedFilename,
        'content-length': String(fileBuffer.length),
      },
    });

    await s3Client.send(putCommand);

    // Log upload event without sensitive data
    console.log(JSON.stringify({
      event: 'file_uploaded',
      s3Key,
      contentType: validatedContentType,
      fileSize: fileBuffer.length,
      timestamp: new Date().toISOString(),
      // Do not log sourceIp, API keys, or file content
    }));

    return buildResponse(200, {
      message: 'File uploaded successfully',
      fileId: uniqueId,
      filename: sanitizedFilename,
      size: fileBuffer.length,
    });
  } catch (error) {
    // Log error details server-side but don't expose them to the client
    console.error(JSON.stringify({
      event: 'upload_error',
      errorMessage: error.message,
      timestamp: new Date().toISOString(),
    }));

    return buildResponse(500, { error: 'Internal server error' });
  }
};